// v4.6: CS Hire Readiness Score Capping (Batch 4 Fix 4.3)
let scoreCapped = false;
let scoreCapReason = null;

const csHireLikelihood = (evaluation.cs_hire_likelihood || '').toLowerCase();

// Graduated caps: unlikely=65, low=75 (Opus review improvement)
if (csHireLikelihood === 'unlikely') {
  if (finalScore > 65) {
    scoreCapped = true;
    scoreCapReason = 'Score capped from ' + finalScore + ' to 65: CS hire likelihood is unlikely';
    finalScore = 65;
  }
} else if (csHireLikelihood === 'low') {
  if (finalScore > 75) {
    scoreCapped = true;
    scoreCapReason = 'Score capped from ' + finalScore + ' to 75: CS hire likelihood is low';
    finalScore = 75;
  }
}

// v4.7: Apply headcount penalty modifier
if (prev.headcount_penalty_modifier && prev.headcount_penalty_modifier < 0) {
  const beforeHeadcount = finalScore;
  finalScore = Math.max(0, finalScore + prev.headcount_penalty_modifier);
  if (!scoreCapped) {
    scoreCapReason = 'Headcount penalty: ' + prev.headcount_penalty_modifier + ' (from ' + beforeHeadcount + ' to ' + finalScore + ')';
  } else {
    scoreCapReason = scoreCapReason + ' | Headcount penalty: ' + prev.headcount_penalty_modifier;
  }
}

