  // Return empty matches for invalid company names
  return [{
    json: {
      ...companyData,
      hasActiveJobPosting: false,
      hasCXJobPosting: false,
      matchingJobTitles: '',
      hasNetworkConnection: false,
      connectionName: '',
      connectionLinkedInURL: '',
      _jobMatchCount: 0,
      _connectionMatchCount: 0,
    }
  }];
}

// For short names (< 4 chars), use exact match only to avoid false positives
const useExactOnly = companyNameClean.length < 4;

// --- JOB LISTINGS MATCHING ---
let jobResults = [];
try {
  jobResults = $('Search Job Listings').all() || [];
} catch(e) {
  console.error('Search Job Listings error:', e.message);
  jobResults = [];
}

const matchedJobs = jobResults.filter(job => {
  const jobCompany = (job.json.Company || '').toLowerCase()
    .replace(/[.,\/#!$%\^&\*;:{}=\-_`~()]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
  if (!jobCompany) return false;
  if (useExactOnly) return jobCompany === companyNameClean;
  return jobCompany === companyNameClean ||
         jobCompany.includes(companyNameClean) ||
         companyNameClean.includes(jobCompany);
});

const hasActiveJob = matchedJobs.length > 0;
const jobTitles = matchedJobs.map(j => j.json['Job Title']).filter(Boolean);

// CX/CS/Support job detection
const CX_PATTERNS = [
  /customer success/i,
  /customer support/i,
  /customer experience/i,
  /client success/i,
  /client services/i,
  /\bcs\b.*(?:manager|lead|director|vp|head)/i,
  /\bcx\b.*(?:manager|lead|director|vp|head)/i,
  /support.*(?:manager|lead|director|vp|head)/i,
  /(?:head|vp|director).*(?:support|success|experience)/i,
  /implementation/i,
  /onboarding.*(?:manager|lead|director)/i,
];

const hasCXJob = matchedJobs.some(job => {
  const title = job.json['Job Title'] || '';
  return CX_PATTERNS.some(p => p.test(title));
});

// --- LINKEDIN CONNECTIONS MATCHING ---
let connectionResults = [];
try {
  connectionResults = $('Search LinkedIn Connections').all() || [];
} catch(e) {
  console.error('Search LinkedIn Connections error:', e.message);
  connectionResults = [];
}

const matchedConnections = connectionResults.filter(conn => {
  const connCompany = (conn.json['Company Normalized'] || conn.json['Company'] || '')
    .toLowerCase()
    .replace(/[.,\/#!$%\^&\*;:{}=\-_`~()]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
  if (!connCompany) return false;
  if (useExactOnly) return connCompany === companyNameClean;
  return connCompany === companyNameClean ||
         connCompany.includes(companyNameClean) ||
         companyNameClean.includes(connCompany);
});

const hasNetworkConnection = matchedConnections.length > 0;

// Pick the most relevant connection (prefer senior roles)
let connectionName = '';
let connectionURL = '';
if (hasNetworkConnection) {
  const SENIORITY_KEYWORDS = /vp|vice president|director|head|chief|founder|ceo|coo|cro|cto/i;
  const sorted = matchedConnections.sort((a, b) => {
    const aScore = SENIORITY_KEYWORDS.test(a.json.Position || '') ? 1 : 0;
    const bScore = SENIORITY_KEYWORDS.test(b.json.Position || '') ? 1 : 0;
    return bScore - aScore;
  });
  connectionName = sorted[0].json.Name || '';
  connectionURL = sorted[0].json['LinkedIn URL'] || '';
}

// --- OUTPUT ---
// Merge with existing company data and pass through
return [{
  json: {
    ...companyData,
    hasActiveJobPosting: hasActiveJob,
    hasCXJobPosting: hasCXJob,
    matchingJobTitles: jobTitles.join(', '),
    hasNetworkConnection: hasNetworkConnection,
    connectionName: connectionName,
    connectionLinkedInURL: connectionURL,
    _jobMatchCount: matchedJobs.length,
    _connectionMatchCount: matchedConnections.length,
  }
}];
